class circle:
    def __init__(self, radius):
        self.radius=radius
    
    def area(self):
        return 3.*self.radius*self.radius
    
    def perimeter(self):
        return 2*3.*self.radius
    
radius=10
circle1=circle(radius)
area1=circle1.area()
perimeter1=circle1.perimeter()
print("Area is",area1,"\nPerimeter is",perimeter1)